  const relayDelegateNote = config.relay
    ? buildRelayDelegateNote()
    : "";
  const specialistProxyNote = buildSpecialistProxyNote();
  const parallelDelegateNote = buildParallelDelegateNote();
  const memoryBlock = buildMemoryBlock(facts, {
    tail: tailOverride ?? config.memoryPreambleTail,
    topics: config.memoryPreambleTopics,
