  agentCommand?: string,
): {
  sendFileNote: string;
  askNote: string;
  scheduleNote: string;
  skillUsedNote: string;
  goalDoneNote: string;
  restartNote: string;
  stickerNote: string;
  wikiQueryNote: string;
  skillProposeNote: string;
  continueNote: string;
  relayDelegateNote: string;
  specialistProxyNote: string;
  parallelDelegateNote: string;
  rtkNote: string;
