/**
 * Environment preamble: tells the agent where this bridge stores memory,
 * skills, agent config files, and which Telegram user owns the session.
 * Skills and long-term notes can reference these as ${MEMORY_DIR},
 * ${SKILL_DIR}, ${AGENT_CONFIG_DIR}, ${USER_ID} rather than hard-coding
 * machine-specific paths — so the same SKILL.md works on the Kiro box,
 * the Codex box, and the Claude box.
 *
 * Heuristic: agent.command name hints which CLI we're paired with
 * (kiro → ~/.kiro, codex → ~/.codex, claude → ~/.claude). Any of the
 * three variables can be overridden via the matching env var.
 */
/**
 * Build relay delegate tool note from external config file.
 * Reads MEMORY_DIR/config/relay-peers.json (fallback: AGENT_CONFIG_DIR).
 */
function buildRelayDelegateNote(): string {
  interface PeerConfig {
    abilities: string[];
    delegateWhen: string[];
  }
  const cfgPath = resolveBridgeConfigPath("relay-peers.json", detectAgentConfigDir());
  let peers: Record<string, PeerConfig>;
  try {
    peers = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    console.warn(`[preamble] relay-peers.json not found at ${cfgPath} — relay delegate tool note disabled`);
    return "";
  }
  const names = Object.keys(peers);
  if (names.length === 0) return "";
  let note = "[Telegram bridge tool: relay delegate]\n";
  note += "`<<RELAY_DELEGATE:<peer>|goal prompt>>`（單行）— 委派任務給另一台機器上的 AI agent。\n";
  note += "也接受 JSON 格式：`<<RELAY_DELEGATE:<peer>|{\"id\":\"<id>\",\"goal\":\"...\",\"context\":\"...\"}>>`\n";
  note += "純文字時 bridge 自動產生 id。goal prompt 不可含 `>>` 或 `|`。\n";
  note += "Bridge 會自動保存你的工作狀態，對方完成後結果靜默注入你的 session。\n\n";
  for (const [name, cfg] of Object.entries(peers)) {
    const extra = (cfg as any).note ? `（${(cfg as any).note}）` : "";
    note += `「${name}」${extra}的能力：\n`;
    for (const a of cfg.abilities) note += `- ${a}\n`;
    note += `\n何時委派給「${name}」：\n`;
    for (const w of cfg.delegateWhen) note += `- ${w}\n`;
    note += "\n";
  }
  note += "格式規則：\n";
  note += "- 純文字格式（推薦）：`<<RELAY_DELEGATE:peer|任務描述>>`\n";
  note += "- JSON 格式（需要帶 context/maxTurns 時）：`<<RELAY_DELEGATE:peer|{\"id\":\"rd_xxx\",\"goal\":\"...\",\"context\":\"...\"}>>` \n";
  note += "- goal/prompt 不可含 `>>` 或 `|`\n";
  note += "- goal 應含五要素：\n";
  note += "  1. 目標與動機（為什麼委派）\n";
  note += "  2. 已知背景（你已掌握的事實、已嘗試的方案、關鍵證據——不要讓 delegate 從零開始）\n";
  note += "  3. 待決問題（具體要 delegate 回答或產出什麼）\n";
  note += "  4. 驗收條件\n";
  note += "  5. 回報格式（只回結論+檔案:行號，長產物存檔回傳路徑）\n";
  note += "- 結果回來後：給 delegate 結論認真權重（獨立視角）；僅在經驗性失敗或一手資料矛盾時才不採納；整合後簡要告知使用者\n";
  note += "- 不要等結果——發出後正常回覆使用者「已委派」即可\n";
  note += "- ⚠️ 重要：發 RELAY_DELEGATE 的 turn 必須包含至少一個 tool call（如 list_facts），否則 token 會被 CLI 吞掉不送出\n";
  note += "[End tool]\n\n";
  return note;
}

function buildSpecialistProxyNote(): string {
  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
  let specs: { name: string; cwd: string }[];
  try {
    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    return "";
  }
  if (!Array.isArray(specs) || specs.length === 0) return "";
  let note = "[Telegram bridge tool: specialist proxy]\n";
  note += "`<<SPECIALIST_PROXY:name|使用者的原始訊息>>`（單行）— 把使用者的訊息轉交給本機 specialist 即時回答。\n";
  note += "進入 proxy 模式後，使用者後續訊息直送 specialist，回覆直送使用者，直到使用者說 /back。\n";
  note += "Specialist 的記憶會回流到你的 facts。proxy 結束時你會收到對話摘要。\n\n";
  note += "可用 specialist：\n";
  for (const s of specs) {
    note += `- ${s.name}（工作目錄：${s.cwd}）\n`;
  }
  note += "\n使用時機：使用者的問題明確屬於某 specialist 的領域，且需要即時互動（不是背景任務）。\n";
  note += "背景任務用 RELAY_DELEGATE；即時對話用 SPECIALIST_PROXY。\n";
  note += "[End tool]\n\n";
  return note;
}

function buildParallelDelegateNote(): string {
  const cfgPath = resolveBridgeConfigPath("specialists.json", detectAgentConfigDir());
  let specs: { name: string }[];
  try {
    specs = JSON.parse(readFileSync(cfgPath, "utf8"));
  } catch {
    return "";
  }
  if (!Array.isArray(specs) || specs.length === 0) return "";
  let note = "[Telegram bridge tool: parallel delegate]\n";
  note += "`<<PARALLEL_DELEGATE:task_id|specialist_name|goal prompt>>`（單行）— 並行委派多個任務給 specialist。\n";
  note += "同一個 turn 放多個 PARALLEL_DELEGATE，bridge 會同時 spawn 多個獨立 instance 並行執行。\n";
  note += "全部完成後結果一次注入你的 session（格式：[PARALLEL_RESULT:task_id]）。\n\n";
  note += "格式規則：\n";
  note += "- task_id：唯一識別碼（如 `pt_1`、`pt_2`）\n";
  note += "- specialist_name：目標 specialist（同一個 name 可以開多個 instance）\n";
  note += "- goal prompt：任務描述（不可含 `>>` 或 `|`），同樣應含三要素：目標與動機 / 驗收條件 / 回報格式\n";
  note += "- 每個 task 獨立 instance，互不干擾——但要避免多個 task 改同一個檔案\n";
  note += "- ⚠️ 同樣需要至少一個 tool call 防止 CLI 吞 token\n\n";
  note += "使用時機：任務可拆成多個獨立子任務且各自耗時 > 1 分鐘（如同時研究多支影片、同時改不同模組）。\n";
  note += "單一任務用 RELAY_DELEGATE；可並行的多任務用 PARALLEL_DELEGATE。\n";
  note += "[End tool]\n\n";
  return note;
}

/**
 * Load the most recent dailylog file (today or yesterday) for preamble context.
 * Returns empty string if no dailylog exists.
 *
 * DISABLED: session-archive recentSummary now provides better, more focused
 * context than the full daily log markdown. The archive gives the last 5
 * assistant replies (150 chars each) which is exactly what the agent needs
 * to resume context, vs. the full daily log which can be 2000+ chars of
 * noise. Keeping the function signature for backward compat with /context.
 */
function buildDailylogBlock(): string {
  return "";
}

/**
 * Read wiki/index.md and extract page titles for the preamble.
 * Returns empty string if wiki doesn't exist yet.
 */
function buildWikiIndexBlock(): string {
  const indexPath = path.join(config.memoryDir, "wiki", "index.md");
  if (!existsSync(indexPath)) return "";
  try {
    const raw = readFileSync(indexPath, "utf8");
    // Extract lines that look like "- [[page-name]] — summary"
    const entries = raw
      .split("\n")
      .filter((l) => /^\s*-\s*\[\[/.test(l));
    if (entries.length === 0) return "";
    return (
      "[Wiki knowledge base — structured pages at ${MEMORY_DIR}/wiki/]\n" +
      entries.join("\n") +
      "\n\n" +
      "When a question relates to a wiki page above, read the full page with\n" +
      "`read` tool at `${MEMORY_DIR}/wiki/<type>/<slug>.md` before answering.\n" +
      "[End wiki]\n\n"
    );
  } catch {
    return "";
  }
}

/**
 * Scan indexes/ directory and list available document tree indexes.
 */
function buildIndexBlock(): string {
  const indexDir = path.join(config.memoryDir, "indexes");
  if (!existsSync(indexDir)) return "";
  try {
    const files = readdirSync(indexDir).filter(
      (f) => f.endsWith(".json") && !f.endsWith(".chunks.json")
    );
    if (files.length === 0) return "";
    const entries: string[] = [];
    for (const file of files) {
      try {
        const raw = JSON.parse(readFileSync(path.join(indexDir, file), "utf8"));
        if (raw.version !== 1) continue;
        entries.push(
          `- ${raw.slug}: ${raw.title} (${raw.total_chars} chars, ${raw.chunk_count} chunks)`
        );
      } catch { /* skip */ }
    }
    if (entries.length === 0) return "";

    let block =
      "[Document indexes — use query_index or read tool to navigate tree, then read specific chunks]\n" +
      entries.join("\n") +
      "\n" +
      "To query: call query_index(slug, question) for auto-navigation, or read ${MEMORY_DIR}/indexes/<slug>.json manually\n" +
      "To ingest new doc: MUST run `py scripts/prep-ingest.py <file> <slug>` first (copies to indexes/sources/), then ingest_prepare\n" +
      "[End indexes]\n\n";

    // Pending ingests from researcher artifacts
    const pending = listPendingIngests();
    if (pending.length > 0) {
      block +=
        "[Pending ingests — researcher artifacts awaiting tree index build]\n" +
        pending.map((p) => `- ${p.slug}: ${p.title} (call ingest_prepare with source="${p.source}")`).join("\n") +
        "\n" +
        "Action: for each pending, call ingest_prepare(source=file_path) then ingest_save to build tree.\n" +
        "Pending files at: ${MEMORY_DIR}/indexes/.pending/<slug>.md\n" +
        "[End pending ingests]\n\n";
    }

    return block;
  } catch {
    return "";
  }
}

function buildScriptsBlock(): string {
  const scriptsDir = path.join(config.sessionCwd, "scripts");
  if (!existsSync(scriptsDir)) return "";
  try {
    const toolFiles = readdirSync(scriptsDir).filter(f => f.startsWith("tool-"));
    if (toolFiles.length === 0) return "";
    const entries: string[] = [];
    for (const file of toolFiles) {
      try {
        const content = readFileSync(path.join(scriptsDir, file), "utf8");
        const lines = content.split(/\r?\n/).slice(0, 5);
        const docLine = lines.find(l => /^(\/\/|#)\s*TOOL:/.test(l));
        const desc = docLine
          ? docLine.replace(/^(\/\/|#)\s*TOOL:\s*/, "").trim()
          : "(no docstring)";
        entries.push(`- ${file}: ${desc}`);
      } catch { entries.push(`- ${file}: (unreadable)`); }
    }
    return (
      "[Available scripts — agent-developed tools in scripts/]\n" +
      entries.join("\n") + "\n" +
      "Run with: node scripts/<file> or python scripts/<file>\n" +
      "[End scripts]\n\n"
    );
  } catch { return ""; }
}

/**
 * Reads ${MEMORY_DIR}/user-profile.md and wraps it as a preamble section.
 * This gives the agent a structured snapshot of the user's identity,
 * communication style, and preferences — separate from the volatile facts.
 */
function buildUserProfileBlock(): string {
  const profilePath = path.join(config.memoryDir, "user-profile.md");
  if (!existsSync(profilePath)) return "";
  try {
    const content = readFileSync(profilePath, "utf8").trim();
    if (!content) return "";
    return (
      "[User profile — structured identity and preferences]\n" +
      content + "\n" +
      "[End user profile]\n\n"
    );
  } catch {
    return "";
  }
}

function buildEnvironmentBlock(userId?: number, agentCommand?: string): string {
  const memoryDir = config.memoryDir;
  const agentConfigDir = detectAgentConfigDir(agentCommand);
  const skillDir = detectSkillDir(agentConfigDir);
  const uid = userId !== undefined ? String(userId) : "(not set — session has no authenticated user yet)";
  return (
    "[Environment — machine-specific paths the bridge resolved for this session]\n" +
    "Skills and notes that need filesystem paths should reference these variables,\n" +
    "not hard-coded values. This lets the same SKILL.md work on multiple machines.\n" +
    `- MEMORY_DIR=${memoryDir}\n` +
    `- SKILL_DIR=${skillDir}\n` +
    `- AGENT_CONFIG_DIR=${agentConfigDir}\n` +
    `- USER_ID=${uid}\n` +
    "Conventions: sessions are under ${MEMORY_DIR}/sessions/, archived under\n" +
    "${MEMORY_DIR}/oldSessions/, master fact log at ${MEMORY_DIR}/facts-${USER_ID}.md,\n" +
    "topic shards at ${MEMORY_DIR}/facts_Topic/${USER_ID}/<topic>.md.\n" +
    "Agent-wide config files (agent configs) live under\n" +
    "${AGENT_CONFIG_DIR}/.\n" +
    "Specialist 歷史產出存在 ${MEMORY_DIR}/artifacts/（結構化 JSON），需要時用 read tool 查閱。\n" +
    "[End environment]\n\n" +
    "[Project context — AI.md layered loading]\n" +
    "工作目錄可能有 `AI.md` 檔案記錄該項目/目錄的上下文要點。\n" +
    "規則：讀到或修改某目錄的檔案時，檢查該目錄及上層（最多 3 層）有無 AI.md。\n" +
    "有就用 read tool 讀取作為工作上下文。同 session 同一個 AI.md 只需讀一次。\n" +
    "多層都有時全部讀（根先子後）。AI.md ≤2000 字，寫架構/慣例/踩坑/測試指引。\n" +
    "主動寫入：在某目錄新增≥3檔案、做架構性改動、或踩坑修復時，主動建立/更新 AI.md。\n" +
    "SPEC：任務≥3工項且跨≥2檔案時先開 SPEC.md；完成工項標 [x]；session 結束前更新進度。\n" +
    "預設行為是寫，不是不寫。詳見 POLICIES/proactive-write-policy.md。\n" +
    "CodeGraph：首次對某專案做修改或追呼叫鏈時，用 codegraph_status(projectPath) 檢查該專案有無索引。\n" +
    "有索引→優先用 codegraph_context/trace/impact 而非手動 grep；改函式簽名前必須先 codegraph_impact。\n" +
    "無索引→回報使用者，建議建立。已知有索引的專案以 codegraph_status 回傳為準。\n" +
    "[End project context]\n\n"
  );
}

/**
 * Detect the agent's config home directory (e.g. ~/.kiro, ~/.codex, ~/.claude).
 * This is the parent of SKILL_DIR and also hosts agent-wide artefacts like
 * notebooklm-routing.json or agents/*.json. Env override: AGENT_CONFIG_DIR.
 */
export function detectAgentConfigDir(agentCommand?: string): string {
  const override = process.env.AGENT_CONFIG_DIR;
  if (override && override.trim() !== "") return path.resolve(override);
  const home = process.env.USERPROFILE || process.env.HOME || "";
  if (!home) return "(unknown — set $AGENT_CONFIG_DIR to override)";
  // Heuristic: the agent command name hints which CLI we're paired with.
  // `agentCommand` overrides the static .env value so an /agent hot-swap
  // session gets the RIGHT config home (e.g. ~/.claude, not ~/.kiro).
  const agent = (agentCommand ?? config.agent?.command ?? "").toLowerCase();
  if (agent.includes("codex")) return path.join(home, ".codex");
  if (agent.includes("claude")) return path.join(home, ".claude");
  if (agent.includes("kiro")) return path.join(home, ".kiro");
  // Fallback: try .kiro then .codex
  const kiroDir = path.join(home, ".kiro");
  const codexDir = path.join(home, ".codex");
  if (existsSync(kiroDir)) return kiroDir;
  if (existsSync(codexDir)) return codexDir;
  return kiroDir; // best guess
}

export function detectSkillDir(agentConfigDir?: string): string {
  // Prefer an explicit override so the user can point us at any directory.
  const override = process.env.SKILL_DIR;
  if (override && override.trim() !== "") return path.resolve(override);
  // Otherwise SKILL_DIR is just <agentConfigDir>/skills — keeps the two paths
  // aligned so users only need to override AGENT_CONFIG_DIR in unusual setups.
  const base = agentConfigDir ?? detectAgentConfigDir();
  if (base.startsWith("(unknown")) return "(unknown — set $SKILL_DIR to override)";
  return path.join(base, "skills");
}

export function getFactsPath(userId: number): string {
  return factsPath(userId);
}

export async function writeFacts(userId: number, lines: string[]): Promise<void> {
  await mkdir(config.memoryDir, { recursive: true });
  const ts = new Date().toISOString();
  const body = lines
    .map((l) => l.trim())
    .filter(Boolean)
    .map((l) => `- [${ts}] ${l}`)
    .join("\n");
  await writeFile(factsPath(userId), body + (body ? "\n" : ""), "utf8");
}

